/**
 * @param {unknown[]} inputs
 * @returns {boolean} to break out current process
 * @returns {{type: EntryType; value: unknown}[]}
 *
 * @example
 * const x = inputs[0];
 * const y = inputs[1];
 * return [{type: "number", value: x + y}];
 */
const item = inputs[0];
const source = inputs[1];
const actor = source?.actor;
let value = item;
if (item?.type && item?.type !== "strike" && actor) {
  if (item?.linkedWeapon) {
    value = item.linkedWeapon
  } else {
    const strike = actor?.system?.actions?.find(a => a?.item?.rule?.item?.slug === item?.slug);
    if (strike?.item) {
      value = strike?.item;
    }
  }
}

// Handle NPC strike
const slug = value?.slug ||  game?.pf2e?.system?.sluggify(value.name);
const group = value?.system?.group ?? value?.group;
const base = value?.system?.baseItem ?? value?.baseType;


return [{type: "item", value: value}, {type: "text", value: slug}, {type: "text", value: group}, {type: "text", value: base}];

